mapper.select:
select product_id,name,brand_name,status,created_at from product_items pi join product_brands pb on pi.brand_id = pb.brand_id

    category_id = 1

        and name like concat('%',#{searchMenue},'%')





        and pb.brand_id = #{brandId}

    /* all 부분 정상으로 동작 한다고 함 + where 안에는 as 못씀*/
        and status = #{status}



    order by created_at desc


    order by created_at asc

limit 10 offset #{offSet}

select count(*) from product_items pi join product_brands pb on pi.brand_id = pb.brand_id

    category_id = 1

        and name like concat('%',#{searchMenue},'%')





        and pb.brand_id = #{brandId}

    /* all 부분 정상으로 동작 한다고 함 + where 안에는 as 못씀*/
        and status = #{status}



    order by created_at desc


    order by created_at asc

select report_id,ps.user_id,ps.post_id as target_id,reason,ps.status,ps.created_at,completed_at,admin_note,processed_by, 'post' as report_type, title as title_name ,(select login_id from users u1 where u1.user_id=ps.user_id) as login_id  from post_reports ps join posts p on ps.post_id=p.post_id

        where ps.status=#{status}

union all
select report_id,ur.user_id,target_user_id as target_id,reason,ur.status,ur.created_at,completed_at,admin_note,processed_by,'user' as report_type,login_id as title_name,(select login_id from users u1 where u1.user_id = ur.target_user_id) as login_id  from user_reports ur join users u on u.user_id=ur.user_id

    where ur.status=#{status}

union all
select report_id,gr.user_id,gr.gram_id as target_id,reason,gr.status,gr.created_at,completed_at,admin_note,processed_by, 'gram' as report_type,title as title_name, (select login_id from users u1 where u1.user_id=gr.user_id) as login_id from gram_reports gr join grams g on g.gram_id=gr.gram_id

    where gr.status=#{status}

order by created_at desc limit 5 offset #{offset}

select sum(cnt) from(
    select count(*) as cnt from post_reports

        where status=#{status}

    union all
    select count(*) as cnt  from user_reports

        where status=#{status}

    union all
    select count(*) as cnt from gram_reports

        where status=#{status}

)    as reports
